      function renderHorario() {
        var el = $('horario-tabla-wrap');
        if (horarioItems.length === 0) {
          el.innerHTML = '<div class="empty-msg">Horario vacío. Presiona "+ Agregar fila" para crear el horario.</div>';
          return;
        }
        var dias = ['Lunes','Martes','Miércoles','Jueves','Viernes'];
        var html = '<table class="horario-grid"><thead><tr><th>Hora</th><th>Lunes</th><th>Martes</th><th>Miércoles</th><th>Jueves</th><th>Viernes</th></tr></thead><tbody>';
        horarioItems.forEach(function (row, idx) {
          html += '<tr>';
          html += '<td class="hora-col">' + escapeHtml(row.hora) + '</td>';
          dias.forEach(function (dia) {
            var contenido = row[dia] || '';
            var cssClass = 'clase-cell';
            var display = '';
            if (contenido.toUpperCase() === 'RECESO') { cssClass = 'receso'; display = 'RECESO'; }
            else if (contenido.toUpperCase() === 'ALMUERZO') { cssClass = 'almuerzo'; display = 'ALMUERZO'; }
            else { display = contenido.replace(/\n/g, '<br>'); }
            html += '<td class="' + cssClass + '" data-idx="' + idx + '" data-dia="' + dia + '">' + display + '</td>';
          });
          html += '<td style="padding:0;width:30px;"><button class="btn btn-sm horario-del" data-idx="' + idx + '" style="background:var(--red);color:#fff;padding:.15rem .35rem;font-size:.65rem;"><img src="data:image/svg+xml;base64," width="20" height="20" style="width:12px;height:12px;display:block" alt=""> </button></td>';
          html += '</tr>';
        });
        html += '</tbody></table>';
        el.innerHTML = html;
        // Click en celda para editar
        el.querySelectorAll('.clase-cell').forEach(function (td) {
          td.addEventListener('click', function () {
            var idx = parseInt(this.dataset.idx);
            var dia = this.dataset.dia;
            abrirEditarCelda(idx, dia);
          });
        });
        // Eliminar fila
        el.querySelectorAll('.horario-del').forEach(function (btn) {
          btn.addEventListener('click', function (e) {
            e.stopPropagation();
            var idx = parseInt(this.dataset.idx);
            horarioItems.splice(idx, 1);
            guardarSeccion('horarioItems', horarioItems);
            renderHorario();
            mostrarToast('Fila eliminada.', 'success');
          });
        });
      }

      var editandoIdx = -1;
      var editandoDia = '';

      function abrirEditarCelda(idx, dia) {
        editandoIdx = idx;
        editandoDia = dia;
        var row = horarioItems[idx];
        $('he-hora').value = row.hora || '';
        $('he-lunes').value = row.Lunes || '';
        $('he-martes').value = row.Martes || '';
        $('he-miercoles').value = row['Miércoles'] || '';
        $('he-jueves').value = row.Jueves || '';
        $('he-viernes').value = row.Viernes || '';
        $('horario-edit-title').innerHTML = '<img src="data:image/svg+xml;base64," width="20" height="20" style="width:14px;height:14px;vertical-align:middle" alt=""> Editar celda: ' + dia;
        $('horario-edit-panel').classList.remove('hidden');
        $('he-guardar').dataset.action = 'edit';
      }

      function cerrarPanelHorario() {
        $('horario-edit-panel').classList.add('hidden');
        editandoIdx = -1;
        editandoDia = '';
        $('he-hora').value = '';
        $('he-lunes').value = '';
        $('he-martes').value = '';
        $('he-miercoles').value = '';
        $('he-jueves').value = '';
        $('he-viernes').value = '';
      }

      $('he-cancelar').addEventListener('click', cerrarPanelHorario);
      $('he-guardar').addEventListener('click', function () {
        var hora = $('he-hora').value.trim();
        if (!hora) { mostrarToast('La hora es obligatoria.', 'error'); return; }
        var lunes = $('he-lunes').value.trim();
        var martes = $('he-martes').value.trim();
        var miercoles = $('he-miercoles').value.trim();
        var jueves = $('he-jueves').value.trim();
        var viernes = $('he-viernes').value.trim();
        var datos = { hora: hora, Lunes: lunes, Martes: martes, 'Miércoles': miercoles, Jueves: jueves, Viernes: viernes };
        if (editandoIdx >= 0) {
          horarioItems[editandoIdx] = datos;
        } else {
          horarioItems.push(datos);
        }
        guardarSeccion('horarioItems', horarioItems);
        cerrarPanelHorario();
        renderHorario();
        mostrarToast('Horario guardado.', 'success');
      });

      $('btn-horario-add').addEventListener('click', function () {
        editandoIdx = -1;
        editandoDia = '';
        $('he-hora').value = '';
        $('he-lunes').value = '';
        $('he-martes').value = '';
        $('he-miercoles').value = '';
        $('he-jueves').value = '';
        $('he-viernes').value = '';
        $('horario-edit-title').innerHTML = '<img src="data:image/svg+xml;base64," width="20" height="20" style="width:14px;height:14px;vertical-align:middle" alt=""> Nueva fila horaria';
        $('horario-edit-panel').classList.remove('hidden');
      });
      renderHorario();

